32	  it.todo("sword with enchantment exactly 5 → high-enchantment surcharge applies");
33	  it.todo("sword with enchantment 5 and cursed → both surcharges apply");
34	  it.todo("sword with enchantment 4 → no high-enchantment surcharge");
35	  it.todo("sword with enchantment 4 and cursed → curse surcharge only");
36	
37	  // Rounding in MHPCO's favor (premium up, payout down)
38	  it.todo("premium calculation yielding 197.5 G → 198 G (rounded up)");
