54	
55	  // Both clauses — 50% rule wins
56	  it.todo("dragon sword, enchantment 9, damage 1000 G → payout 400 G (50% wins, then deductible)");
57	  it.todo("dragon sword, enchantment exactly 8, damage 1000 G → payout 400 G (high-enchantment then deductible)");
58	
59	  // Deductible per damage event
